import React from "react";
import {
  onPostChangecreateActin,
  addPostcreateActin,
} from "../../redux/messegData-reducer";
import Contacts from "./Contacts";

const ContactsContainer = () => {
  return (
    <StoreContext>
      {(store) => {
        const addPost = () => {
          store.dispatch(addPostcreateActin());
        };

        const onPostChange = (e) => {
          store.dispatch(onPostChangecreateActin(e));
        };

        return (
          <Contacts
            onPost={onPostChange}
            addPost={addPost}
            messege={store.store.messeges.messegData}
            newMessege={store.store.messeges.newChanges}
          />
        );
      }}
    </StoreContext>
  );
};

export default ContactsContainer;
